class PaymentServiceProvider extends ServiceProvider {
    public function register(): void {
        $this->app->singleton(PaymentGateway::class, function ($app) {
            return match($app['config']['payments.driver']) {
                'stripe' => new StripeGateway($app['config']['services.stripe.key']),
                'paypal' => new PayPalGateway($app['config']['services.paypal.key']),
            };
        });
    }
    public function boot(): void {
        $this->publishes([__DIR__.'/../config/payments.php' => config_path('payments.php')]);
    }
}

